case 'getfunc': {
 if (!isCreator) return payreply(mess.owner)
 if (!text) return payreply(`Contoh: ${prefix}getfunc case2`)

 const fs = require('fs')
 const path = require('path')

 await Asepp.sendMessage(m.chat, { react: { text: "🩸", key: m.key } })

 try {
 const filePath = path.join(__dirname, 'AseppLohya.js') // ganti nama file lu
 const source = fs.readFileSync(filePath, 'utf-8')

 const caseName = text.trim().toLowerCase()
 // Ambil blok case sampe break
 const caseRegex = new RegExp(`case\\s+['"]${caseName}['"]\\s*:[\\s\\S]*?break`, 'i')
 const caseMatch = source.match(caseRegex)

 if (!caseMatch) return payreply(`Case *${text}* ga ketemu 🩸`)

 const caseBlock = caseMatch[0]

 // Cari semua function yg dipanggil pake await
 const funcRegex = /await\s+([a-zA-Z_$][\w$]*)\s*\(([\s\S]*?)\)/g
 let matches = [...caseBlock.matchAll(funcRegex)]

 if (matches.length === 0) return payreply(`Di case *${text}* ga ada function await 🩸`)

 let teks = `*FUNCTION DI CASE: ${text.toUpperCase()}* 🩸\n\n`
 matches.forEach((v, i) => {
 teks += `*${i+1}.* \`${v[1]}(${v[2].trim()})\`\n`
 })

 teks += `\n*Total:* ${matches.length} function`

 // Kalo mau kirim function yg pertama doang
 if (matches[0]) {
 teks += `\n\n*Function Utama:*\n\`\`\`javascript\nawait ${matches[0][1]}(${matches[0][2].trim()})\n\`\`\``
 }

 payreply(teks)

 } catch (e) {
 payreply(`Error: ${e.message}`)
 }
}
break
